import React, { useEffect, useState } from 'react';
import { User, Symptom, Reminder } from '../types';
import { getDailyAffirmation } from '../services/gemini';
import { SONGS, MOODS } from '../constants';

interface DashboardProps {
  user: User;
  symptoms: Symptom[];
  waterIntake: number;
  setWaterIntake: React.Dispatch<React.SetStateAction<number>>;
  waterGoal: number;
  reminders: Reminder[];
  currentSongIndex: number;
  isMusicPlaying: boolean;
  toggleMusic: () => void;
  nextSong: () => void;
  prevSong: () => void;
  setCurrentSongIndex: (index: number) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ 
  user, 
  waterIntake, 
  setWaterIntake, 
  waterGoal, 
  reminders,
  currentSongIndex,
  isMusicPlaying,
  toggleMusic,
  nextSong,
  prevSong,
  setCurrentSongIndex
}) => {
  const [affirmation, setAffirmation] = useState("Loading your daily inspiration...");
  const [selectedMood, setSelectedMood] = useState('Happy');

  useEffect(() => {
    getDailyAffirmation().then(setAffirmation);
  }, []);

  const handleMoodSelect = (mood: typeof MOODS[0]) => {
    setSelectedMood(mood.label);
    const moodSong = SONGS.find(s => s.tags.includes(mood.songTag));
    if (moodSong) {
      const idx = SONGS.indexOf(moodSong);
      if (idx !== -1) setCurrentSongIndex(idx);
    }
  };

  const activeReminders = reminders.filter(r => !r.isCompleted);
  const currentSong = SONGS[currentSongIndex];
  const waterPercentage = Math.min((waterIntake / waterGoal) * 100, 100);

  return (
    <div className="space-y-8 animate-fadeIn pb-12">
      {/* Hero Welcome */}
      <section className="relative overflow-hidden bg-gradient-to-br from-pink-100 via-rose-50 to-pink-100 p-8 rounded-[3rem] shadow-[0_10px_40px_rgba(244,114,182,0.1)] text-pink-600 border border-white/50">
        <div className="relative z-10">
          <div className="flex items-center gap-3 mb-2">
            <h2 className="text-4xl font-serif italic">Hello, {user.name}</h2>
            <span className="text-3xl animate-bounce">✨</span>
          </div>
          <p className="text-sm opacity-80 mb-6 italic font-medium">Your sanctuary is blooming beautifully today.</p>

          <div className="bg-white/60 backdrop-blur-md p-6 rounded-3xl border border-white/60 shadow-sm">
            <p className="text-[10px] font-bold uppercase tracking-widest text-pink-400 mb-2">Daily Whisper</p>
            <p className="text-xl font-serif italic text-pink-700 leading-relaxed">"{affirmation}"</p>
          </div>
        </div>
        <div className="absolute top-0 right-0 -translate-y-6 translate-x-6">
           <span className="text-[12rem] opacity-10 rotate-12">🌸</span>
        </div>
        <div className="absolute bottom-0 left-0 -translate-x-6 translate-y-6">
           <span className="text-[8rem] opacity-5 -rotate-12">🎀</span>
        </div>
      </section>

      {/* Mood Melodies Selection */}
      <section className="bg-white/50 p-6 rounded-[2.5rem] border border-pink-100/50">
        <h3 className="text-lg font-serif text-pink-500 mb-4 px-2 italic flex items-center gap-2">
          <span className="text-xl">🎶</span> Mood Melodies
        </h3>
        <div className="flex gap-3 overflow-x-auto pb-4 scrollbar-hide px-2">
          {MOODS.map((mood) => (
            <button
              key={mood.label}
              onClick={() => handleMoodSelect(mood)}
              className={`flex-shrink-0 flex flex-col items-center gap-2 p-4 rounded-3xl transition-all border-2 ${selectedMood === mood.label ? 'bg-pink-400 border-pink-400 text-white shadow-lg scale-105' : 'bg-white border-pink-50 text-pink-300 hover:border-pink-200'}`}
            >
              <span className="text-2xl">{mood.emoji}</span>
              <span className="text-[10px] font-bold uppercase tracking-tighter">{mood.label}</span>
            </button>
          ))}
        </div>
      </section>

      {/* Partner Reminders */}
      {activeReminders.length > 0 && (
        <section className="bg-indigo-50/50 p-6 rounded-[2.5rem] border border-indigo-100 shadow-sm">
          <h3 className="text-lg font-serif text-indigo-600 mb-4 flex items-center gap-2 px-2">
            <span className="text-xl">💝</span> From {user.partnerName}
          </h3>
          <div className="space-y-3">
            {activeReminders.map(reminder => (
              <div key={reminder.id} className="flex items-center gap-4 bg-white/90 p-5 rounded-3xl shadow-sm border border-indigo-50 hover:scale-[1.02] transition-transform">
                <div className="w-10 h-10 bg-indigo-100 rounded-full flex items-center justify-center text-xl">💌</div>
                <div>
                  <p className="text-base font-serif italic text-indigo-900 leading-tight">{reminder.text}</p>
                  <p className="text-[9px] text-indigo-400 font-bold uppercase tracking-widest mt-1">{reminder.time}</p>
                </div>
              </div>
            ))}
          </div>
        </section>
      )}

      {/* Main Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {/* Blooming Water Tracker */}
        <div className="bg-white p-8 rounded-[3rem] shadow-sm border border-pink-50 flex flex-col items-center justify-center text-center group">
          <h3 className="text-xl font-serif text-pink-500 mb-6 flex items-center gap-2 italic">
            <span className="text-2xl">💧</span> Hydration Bloom
          </h3>
          <div className="relative w-32 h-32 mb-6">
            <div className="absolute inset-0 border-4 border-pink-50 rounded-full"></div>
            <div 
              className="absolute inset-0 border-4 border-pink-400 rounded-full transition-all duration-1000 ease-out" 
              style={{ clipPath: `inset(${100 - waterPercentage}% 0 0 0)` }}
            ></div>
            <div className="absolute inset-0 flex flex-col items-center justify-center">
              <span className="text-3xl animate-pulse">🌸</span>
              <span className="text-[10px] font-bold text-pink-400 mt-1 uppercase">{waterPercentage.toFixed(0)}%</span>
            </div>
          </div>
          <p className="text-sm font-serif italic text-pink-600 mb-6">
            {waterIntake} of {waterGoal} glasses bloomed
          </p>
          <div className="flex gap-3">
            <button 
              onClick={() => setWaterIntake(Math.max(0, waterIntake - 1))}
              className="w-10 h-10 rounded-full bg-pink-50 text-pink-500 flex items-center justify-center shadow-sm hover:bg-pink-100"
            >
              -
            </button>
            <button 
              onClick={() => setWaterIntake(Math.min(waterGoal, waterIntake + 1))}
              className="px-6 h-10 rounded-full bg-pink-500 text-white font-bold text-[10px] uppercase tracking-widest shadow-md hover:scale-105 transition-transform"
            >
              Add Drop
            </button>
            <button 
              onClick={() => setWaterIntake(waterGoal)}
              className="w-10 h-10 rounded-full bg-pink-50 text-pink-500 flex items-center justify-center shadow-sm hover:bg-pink-100"
            >
              ✨
            </button>
          </div>
        </div>

        {/* Cycle Mini View */}
        <div className="bg-white p-8 rounded-[3rem] shadow-sm border border-pink-50 flex flex-col justify-between">
          <div>
            <h3 className="text-xl font-serif text-pink-500 mb-6 flex items-center gap-2 italic">
              <span className="text-2xl">🌙</span> Divine Rhythm
            </h3>
            <div className="space-y-4">
              <div className="flex items-center justify-between bg-pink-50/50 p-4 rounded-2xl">
                <span className="text-xs font-bold text-pink-400 uppercase">Phase</span>
                <span className="text-lg font-serif italic text-pink-600">Follicular Bloom</span>
              </div>
              <div className="flex items-center justify-between bg-teal-50/50 p-4 rounded-2xl">
                <span className="text-xs font-bold text-teal-400 uppercase">Ovulation In</span>
                <span className="text-lg font-serif italic text-teal-600">6 Beautiful Days</span>
              </div>
            </div>
          </div>
          <button className="mt-8 w-full py-4 bg-gradient-to-r from-pink-400 to-rose-400 text-white rounded-3xl text-[10px] font-bold uppercase tracking-widest shadow-lg shadow-pink-100 hover:scale-[1.02] transition-transform">
            Log Your Feelings
          </button>
        </div>
      </div>

      {/* Featured Music Room Entry */}
      <section className="bg-white p-8 rounded-[3rem] shadow-sm border border-pink-50 overflow-hidden relative group">
        <div className="flex flex-col md:flex-row items-center gap-8">
          <div className="relative w-40 h-40 flex-shrink-0">
            <div className={`absolute inset-0 bg-gradient-to-br from-pink-200 to-rose-300 rounded-full shadow-2xl transition-all duration-1000 ${isMusicPlaying ? 'rotate-[360deg] animate-[spin_12s_linear_infinite]' : ''}`}>
               <div className="absolute inset-4 bg-white/30 backdrop-blur-sm rounded-full border border-white/40 flex items-center justify-center text-6xl">
                 {currentSong.coverEmoji}
               </div>
            </div>
            <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-4 h-4 bg-white rounded-full shadow-inner z-10"></div>
          </div>

          <div className="flex-1 text-center md:text-left space-y-2">
            <p className="text-[10px] font-bold text-pink-300 uppercase tracking-widest mb-1 flex items-center justify-center md:justify-start gap-2">
              <span className="w-4 h-[1px] bg-pink-100"></span> Now Serenading <span className="w-4 h-[1px] bg-pink-100"></span>
            </p>
            <h3 className="text-3xl font-serif text-pink-600 italic leading-tight">{currentSong.title}</h3>
            <p className="text-sm text-pink-400 font-bold uppercase tracking-widest mb-6">{currentSong.artist}</p>

            <div className="flex items-center justify-center md:justify-start gap-6 pt-4">
              <button onClick={prevSong} className="text-3xl text-pink-200 hover:text-pink-400 transition-colors">⏮</button>
              <button 
                onClick={toggleMusic}
                className="w-14 h-14 bg-pink-500 text-white rounded-full flex items-center justify-center shadow-xl shadow-pink-200 hover:scale-110 active:scale-95 transition-all text-xl"
              >
                {isMusicPlaying ? '⏸' : '▶'}
              </button>
              <button onClick={nextSong} className="text-3xl text-pink-200 hover:text-pink-400 transition-colors">⏭</button>
            </div>
          </div>
        </div>
      </section>
    </div>
  );
};

export default Dashboard;

import React from 'react';
import { SelfCareTask } from '../types';

interface SelfCareProps {
  tasks: SelfCareTask[];
  setTasks: React.Dispatch<React.SetStateAction<SelfCareTask[]>>;
}

const SelfCare: React.FC<SelfCareProps> = ({ tasks, setTasks }) => {
  const toggleTask = (id: string) => {
    setTasks(tasks.map(t => t.id === id ? { ...t, completed: !t.completed } : t));
  };

  const rituals = [
    { id: '1', task: 'Warm rose tea ritual', icon: '🍵' },
    { id: '2', task: 'Gentle facial massage', icon: '💆‍♀️' },
    { id: '3', task: 'Read 10 pages of inspiration', icon: '📖' },
    { id: '4', task: 'Mirror affirmations', icon: '🪞' },
    { id: '5', task: 'Silk pillowcase prep', icon: '☁️' },
  ];

  return (
    <div className="space-y-8 animate-fadeIn pb-12">
      <header className="text-center">
        <h2 className="text-4xl font-serif text-pink-500 italic mb-2">Divine Rituals</h2>
        <p className="text-sm text-pink-300 italic font-medium">Self-love is your highest frequency</p>
      </header>

      <div className="bg-white p-8 md:p-12 rounded-[3.5rem] shadow-sm border border-pink-50">
        <div className="space-y-5">
          {tasks.map((task, idx) => (
            <div 
              key={task.id} 
              onClick={() => toggleTask(task.id)}
              className={`flex items-center gap-5 p-6 rounded-3xl cursor-pointer group transition-all border-2 ${task.completed ? 'bg-pink-50 border-transparent' : 'bg-white border-pink-50 hover:border-pink-200'}`}
            >
              <div className={`w-10 h-10 rounded-full border-2 flex items-center justify-center transition-all ${task.completed ? 'bg-pink-400 border-pink-400 shadow-md' : 'border-pink-200 bg-white group-hover:bg-pink-50'}`}>
                {task.completed ? <span className="text-white text-sm">✓</span> : <span className="text-[10px] text-pink-200">{idx + 1}</span>}
              </div>
              <div className="flex-1">
                <span className={`text-xl font-serif italic transition-all block ${task.completed ? 'text-pink-300 line-through opacity-70' : 'text-pink-600'}`}>
                  {task.task}
                </span>
                {task.completed && <span className="text-[8px] font-bold text-pink-400 uppercase tracking-widest">Completed with Love</span>}
              </div>
            </div>
          ))}
        </div>

        <div className="mt-12 p-8 bg-gradient-to-br from-rose-50 to-pink-50 rounded-[2.5rem] border border-rose-100 text-center shadow-inner">
           <p className="text-[10px] font-bold text-rose-400 uppercase tracking-widest mb-2">Today's Bloom Progress</p>
           <p className="text-4xl font-serif italic text-rose-600 mb-2">
             {tasks.filter(t => t.completed).length} / {tasks.length}
           </p>
           <div className="w-32 h-1 bg-white/50 rounded-full mx-auto overflow-hidden">
              <div 
                className="h-full bg-rose-400 transition-all duration-700" 
                style={{ width: `${(tasks.filter(t => t.completed).length / tasks.length) * 100}%` }}
              ></div>
           </div>
        </div>
      </div>

      <section className="bg-white p-10 rounded-[3.5rem] shadow-sm border border-pink-50 relative overflow-hidden">
        <div className="absolute top-0 right-0 p-10 opacity-5 -rotate-12">
          <span className="text-[10rem]">💎</span>
        </div>
        <h3 className="text-2xl font-serif text-pink-500 mb-6 italic">Sacred Wisdom</h3>
        <ul className="space-y-6 text-base text-gray-600 font-serif italic">
           <li className="flex gap-4 items-start">
             <span className="flex-shrink-0 w-8 h-8 rounded-full bg-pink-100 flex items-center justify-center text-pink-500 shadow-sm">✨</span>
             <p className="leading-relaxed pt-1">Rest is not a luxury; it is a vital part of your cycle's harmony. Honor your energy dips with grace.</p>
           </li>
           <li className="flex gap-4 items-start">
             <span className="flex-shrink-0 w-8 h-8 rounded-full bg-pink-100 flex items-center justify-center text-pink-500 shadow-sm">🌸</span>
             <p className="leading-relaxed pt-1">Massaging your lower abdomen with lavender oil can significantly lower cortisol and ease internal tension.</p>
           </li>
        </ul>
      </section>
    </div>
  );
};

export default SelfCare;

import React, { useState, useEffect, useRef } from 'react';
import { User, Symptom, DiaryEntry, SelfCareTask, AppTheme, Reminder, BirthControlLog, Song } from './types';
import Auth from './components/Auth';
import Dashboard from './components/Dashboard';
import PeriodTracker from './components/PeriodTracker';
import SelfCare from './components/SelfCare';
import YogaTutorials from './components/YogaTutorials';
import Diary from './components/Diary';
import PartnerMode from './components/PartnerMode';
import WaterTracker from './components/WaterTracker';
import Education from './components/Education';
import PregnancyTracker from './components/PregnancyTracker';
import Settings from './components/Settings';
import MusicRoom from './components/MusicRoom';
import { playWelcomeVoice } from './services/gemini';
import { THEMES, SONGS } from './constants';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [symptoms, setSymptoms] = useState<Symptom[]>([]);
  const [diaryEntries, setDiaryEntries] = useState<DiaryEntry[]>([]);
  const [waterIntake, setWaterIntake] = useState(0);
  const [waterGoal, setWaterGoal] = useState(8);
  const [isMusicPlaying, setIsMusicPlaying] = useState(false);
  const [currentSongIndex, setCurrentSongIndex] = useState(0);
  const [volume, setVolume] = useState(0.3);
  const [reminders, setReminders] = useState<Reminder[]>([]);
  const [bcLogs, setBcLogs] = useState<BirthControlLog[]>([]);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  const [selfCareTasks, setSelfCareTasks] = useState<SelfCareTask[]>([
    { id: '1', task: 'Drink warm tea ritual', completed: false },
    { id: '2', task: 'Facial massage', completed: false },
    { id: '3', task: 'Meditation for 5 mins', completed: false },
    { id: '4', task: 'Gentle yoga stretch', completed: false },
  ]);

  const handleLogin = (userData: User) => {
    const fullUser: User = {
      ...userData,
      theme: userData.theme || 'rose',
      isPregnancyMode: userData.isPregnancyMode || false,
      diaryPin: userData.diaryPin || '1234',
      favoriteSongs: userData.favoriteSongs || [],
      customSongs: userData.customSongs || [],
      birthControlConfig: userData.birthControlConfig || {
        method: 'Pill',
        frequency: 'daily',
        reminderTime: '09:00',
        enabled: false
      }
    };
    setUser(fullUser);
    playWelcomeVoice(fullUser.name);
    setIsMusicPlaying(true);
  };

  const updateTheme = (newTheme: AppTheme) => {
    if (user) {
      setUser({ ...user, theme: newTheme });
    }
  };

  const toggleFavoriteSong = (songId: string) => {
    if (!user) return;
    const currentFavs = user.favoriteSongs || [];
    const newFavs = currentFavs.includes(songId) 
      ? currentFavs.filter(id => id !== songId) 
      : [...currentFavs, songId];
    setUser({ ...user, favoriteSongs: newFavs });
  };

  const addCustomSong = (song: Song) => {
    if (!user) return;
    const newCustoms = [...(user.customSongs || []), song];
    setUser({ ...user, customSongs: newCustoms });
  };

  const togglePregnancy = () => {
    if (user) {
      setUser({ 
        ...user, 
        isPregnancyMode: !user.isPregnancyMode,
        pregnancyStartDate: !user.isPregnancyMode ? new Date().toISOString() : undefined 
      });
    }
  };

  const updateBCConfig = (config: User['birthControlConfig']) => {
    if (user && config) {
      setUser({ ...user, birthControlConfig: config });
    }
  };

  const toggleMusic = () => {
    setIsMusicPlaying(!isMusicPlaying);
  };

  const fullLibrary = [...SONGS, ...(user?.customSongs || [])];

  const nextSong = () => {
    setCurrentSongIndex((prev) => (prev + 1) % fullLibrary.length);
  };

  const prevSong = () => {
    setCurrentSongIndex((prev) => (prev - 1 + fullLibrary.length) % fullLibrary.length);
  };

  useEffect(() => {
    if (audioRef.current && fullLibrary[currentSongIndex]?.source === 'internal') {
      if (isMusicPlaying) {
        audioRef.current.play().catch(e => console.log("Autoplay blocked", e));
      } else {
        audioRef.current.pause();
      }
    }
  }, [isMusicPlaying, currentSongIndex, user?.customSongs]);

  useEffect(() => {
    if (audioRef.current) {
      audioRef.current.volume = volume;
    }
  }, [volume]);

  if (!user) {
    return <Auth onLogin={handleLogin} />;
  }

  const currentThemeData = THEMES[user.theme || 'rose'];
  const themeClass = `text-${currentThemeData.primary}`;

  const renderContent = () => {
    if (user.isPartner) {
      return <PartnerMode user={user} reminders={reminders} setReminders={setReminders} />;
    }

    switch (activeTab) {
      case 'dashboard':
        return (
          <Dashboard 
            user={user} 
            symptoms={symptoms} 
            waterIntake={waterIntake} 
            setWaterIntake={setWaterIntake} 
            waterGoal={waterGoal} 
            reminders={reminders} 
            currentSongIndex={currentSongIndex}
            isMusicPlaying={isMusicPlaying}
            toggleMusic={toggleMusic}
            nextSong={nextSong}
            prevSong={prevSong}
            setCurrentSongIndex={setCurrentSongIndex}
          />
        );
      case 'cycle':
        return user.isPregnancyMode 
          ? <PregnancyTracker user={user} /> 
          : <PeriodTracker 
              user={user} 
              symptoms={symptoms} 
              setSymptoms={setSymptoms} 
              bcLogs={bcLogs} 
              setBcLogs={setBcLogs}
              onUpdateBCConfig={updateBCConfig}
            />;
      case 'edu':
        return <Education />;
      case 'water':
        return <WaterTracker waterIntake={waterIntake} setWaterIntake={setWaterIntake} waterGoal={waterGoal} setWaterGoal={setWaterGoal} />;
      case 'music':
        return <MusicRoom 
          user={user} 
          onToggleFavorite={toggleFavoriteSong} 
          currentSongIndex={currentSongIndex} 
          onSelectSong={setCurrentSongIndex} 
          isMusicPlaying={isMusicPlaying} 
          onTogglePlay={toggleMusic} 
          onAddCustomSong={addCustomSong}
        />;
      case 'diary':
        return <Diary entries={diaryEntries} setEntries={setDiaryEntries} user={user} />;
      case 'selfcare':
        return <SelfCare tasks={selfCareTasks} setTasks={setSelfCareTasks} />;
      case 'settings':
        return <Settings />;
      default:
        return <Dashboard user={user} symptoms={symptoms} waterIntake={waterIntake} setWaterIntake={setWaterIntake} waterGoal={waterGoal} reminders={reminders} currentSongIndex={currentSongIndex} isMusicPlaying={isMusicPlaying} toggleMusic={toggleMusic} nextSong={nextSong} prevSong={prevSong} setCurrentSongIndex={setCurrentSongIndex} />;
    }
  };

  const currentTrack = fullLibrary[currentSongIndex];

  return (
    <div className={`min-h-screen pb-28 ${currentThemeData.bg} selection:bg-pink-100 transition-colors duration-500`}>
      <audio 
        ref={audioRef}
        src={currentTrack?.source === 'internal' ? currentTrack.url : undefined} 
        onEnded={nextSong}
        loop={false}
      />

      <header className="px-6 pt-10 pb-6 flex justify-between items-center bg-white/80 backdrop-blur-md shadow-sm sticky top-0 z-[60] border-b border-pink-50">
        <div className="cursor-pointer" onClick={() => setActiveTab('dashboard')}>
          <h1 className={`text-3xl font-serif italic ${themeClass}`}>Lumina</h1>
          <div className="flex gap-1 mt-1">
            {(Object.keys(THEMES) as AppTheme[]).map(t => (
              <button 
                key={t}
                onClick={(e) => { e.stopPropagation(); updateTheme(t); }}
                className={`w-3 h-3 rounded-full border border-white shadow-sm transition-transform hover:scale-125 ${t === 'rose' ? 'bg-pink-400' : t === 'lavender' ? 'bg-purple-400' : t === 'mint' ? 'bg-teal-400' : 'bg-orange-400'} ${user.theme === t ? 'ring-2 ring-offset-2 ring-gray-300' : ''}`}
              />
            ))}
          </div>
        </div>

        <div className="flex items-center gap-4">
          {!user.isPartner && (
            <button 
              onClick={togglePregnancy}
              className={`text-[9px] font-bold px-4 py-1.5 rounded-full border transition-all ${user.isPregnancyMode ? 'bg-indigo-500 text-white border-indigo-500 shadow-md' : 'bg-white text-gray-400 border-gray-200'}`}
            >
              {user.isPregnancyMode ? 'PREGNANCY MODE' : 'OFF'}
            </button>
          )}

          <div className="flex items-center gap-2 bg-pink-50/50 px-3 py-1.5 rounded-full border border-pink-100/50">
            <button 
              onClick={() => {
                if (currentTrack?.source !== 'internal') {
                  window.open(currentTrack.url, '_blank');
                } else {
                  toggleMusic();
                }
              }} 
              className="text-xs"
            >
              {currentTrack?.source !== 'internal' ? '↗' : (isMusicPlaying ? '⏸️' : '▶️')}
            </button>
            <input 
              type="range" min="0" max="1" step="0.01" value={volume} 
              onChange={(e) => setVolume(parseFloat(e.target.value))}
              className="w-10 h-1 accent-pink-400"
            />
          </div>

          <button onClick={() => setActiveTab('settings')} className="p-2 text-gray-400 hover:text-pink-400 transition-colors">
            ⚙️
          </button>
        </div>
      </header>

      <main className="max-w-4xl mx-auto px-4 mt-8 pb-10">
        {renderContent()}
      </main>

      {!user.isPartner && (
