import React, { useEffect, useState } from 'react';
import { User, Reminder } from '../types';
import { getGiftIdeas, getCommunicationTips, getLoveNoteIdeas } from '../services/gemini';

interface PartnerModeProps {
  user: User;
  reminders: Reminder[];
  setReminders: React.Dispatch<React.SetStateAction<Reminder[]>>;
}

const PartnerMode: React.FC<PartnerModeProps> = ({ user, reminders, setReminders }) => {
  const [giftIdeas, setGiftIdeas] = useState<string[]>([]);
  const [commTips, setCommTips] = useState<string>('');
  const [loveNotes, setLoveNotes] = useState<string[]>([]);
  const [loading, setLoading] = useState(true);
  const [newReminderText, setNewReminderText] = useState('');
  const [newReminderTime, setNewReminderTime] = useState('');
  const [activeTab, setActiveTab] = useState<'support' | 'ideas' | 'notes'>('support');

  const currentPhase = "Luteal"; // This would ideally be calculated dynamically based on user.lastPeriodStart

  useEffect(() => {
    setLoading(true);
    Promise.all([
      getGiftIdeas(currentPhase),
      getCommunicationTips(currentPhase),
      getLoveNoteIdeas(currentPhase)
    ]).then(([ideas, tips, notes]) => {
      setGiftIdeas(ideas);
      setCommTips(tips);
      setLoveNotes(notes);
      setLoading(false);
    });
  }, [currentPhase]);

  const addReminder = () => {
    if (!newReminderText.trim()) return;
    const reminder: Reminder = {
      id: Math.random().toString(36).substr(2, 9),
      text: newReminderText,
      time: newReminderTime || 'Today',
      isCompleted: false
    };
    setReminders([...reminders, reminder]);
    setNewReminderText('');
    setNewReminderTime('');
  };

  const toggleReminder = (id: string) => {
    setReminders(reminders.map(r => r.id === id ? { ...r, isCompleted: !r.isCompleted } : r));
  };

  const deleteReminder = (id: string) => {
    setReminders(reminders.filter(r => r.id !== id));
  };

