        <div className="relative z-10 flex flex-col md:flex-row md:items-center justify-between gap-6">
          <div>
            <h2 className="text-4xl font-serif mb-2 italic tracking-tight">Support Sanctuary</h2>
            <p className="text-sm opacity-60 mb-6 italic font-medium">Being the best partner for {user.partnerName} today.</p>
            <div className="inline-flex items-center gap-2 bg-pink-500 text-white px-4 py-2 rounded-full text-[10px] font-bold uppercase tracking-widest shadow-md">
              <span className="animate-pulse">🌸</span> Current Phase: {currentPhase}
            </div>
          </div>
          <div className="bg-white/80 backdrop-blur-md p-6 rounded-[2.5rem] border border-white shadow-lg flex-shrink-0 w-full md:w-64">
            <p className="text-[10px] font-bold uppercase tracking-widest text-indigo-400 mb-3">Today's Insight</p>
            <p className="text-xs text-indigo-700 font-serif italic leading-relaxed">
