          </div>
        </div>
        <div className="absolute -bottom-20 -right-20 text-[20rem] text-pink-100 opacity-20 rotate-12 pointer-events-none">🌸</div>
      </header>

      {/* Internal Navigation */}
      <nav className="flex bg-white/50 p-1.5 rounded-3xl border border-pink-100/50 shadow-sm sticky top-24 z-40 backdrop-blur-md">
        <button 
