const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function getDailyAffirmation(): Promise<string> {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: "Generate a super girly, empowering, and poetic daily affirmation for a woman's wellness app. Keep it short and beautiful.",
      config: {
        systemInstruction: "You are a supportive and elegant wellness coach.",
      }
    });
    return response.text || "You are blooming exactly as you should.";
  } catch (error) {
    console.error("Affirmation Error:", error);
    return "You are a masterpiece in progress.";
  }
}

export async function getProductAdvice(product: string, concern: string): Promise<string> {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `I am nervous about using a ${product}. My specific concern is: ${concern}. Please give me some comforting, big-sisterly advice that is medically sound but very gentle and empowering.`,
      config: {
        systemInstruction: "You are a kind, wise older sister and wellness expert.",
      }
    });
    return response.text || "It's completely normal to be nervous! You're doing great, and your body is amazing.";
  } catch (error) {
    return "Take a deep breath. You are in control of your body, and it's okay to take it slow. You've got this, beautiful!";
  }
}

export async function playWelcomeVoice(name: string) {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: `Say in a warm, elegant, and welcoming female voice: Hello beautiful ${name}. Welcome back to your sanctuary. I hope you're feeling wonderful today.` }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: 'Kore' },
          },
        },
      },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (base64Audio) {
      const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      const audioBuffer = await decodeAudioData(
        decodeBase64(base64Audio),
        audioContext,
        24000,
        1
      );
      const source = audioContext.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(audioContext.destination);
      source.start();
    }
  } catch (error) {
    console.error("Welcome Voice Error:", error);
  }
}

