            <p className="text-[10px] font-bold uppercase tracking-widest text-pink-400 mb-2">Daily Whisper</p>
            <p className="text-xl font-serif italic text-pink-700 leading-relaxed">"{affirmation}"</p>
          </div>
        </div>
        <div className="absolute top-0 right-0 -translate-y-6 translate-x-6">
           <span className="text-[12rem] opacity-10 rotate-12">🌸</span>
        </div>
        <div className="absolute bottom-0 left-0 -translate-x-6 translate-y-6">
           <span className="text-[8rem] opacity-5 -rotate-12">🎀</span>
        </div>
      </section>

      {/* Received Comforts (Partner Interactions) */}
      {user.receivedComforts && user.receivedComforts.length > 0 && (
        <section className="bg-gradient-to-r from-pink-400 to-rose-400 p-8 rounded-[3rem] text-white shadow-xl animate-fadeIn relative overflow-hidden group">
           <div className="relative z-10">
              <h3 className="text-xs font-bold uppercase tracking-[0.3em] opacity-80 mb-4 flex items-center gap-2">
                 <span className="animate-ping w-2 h-2 bg-white rounded-full"></span> 
                 A gift from {user.partnerName}
              </h3>
              <div className="flex items-center gap-6">
                 <div className="w-20 h-20 bg-white/20 backdrop-blur-md rounded-full flex items-center justify-center text-5xl shadow-inner border border-white/30">
                    {user.receivedComforts[0].type === 'hug' ? '🫂' : 
                     user.receivedComforts[0].type === 'tea' ? '🍵' : 
                     user.receivedComforts[0].type === 'flower' ? '💐' : 
                     user.receivedComforts[0].type === 'chocolate' ? '🍫' : '✨'}
                 </div>
                 <div>
                    <p className="text-2xl font-serif italic">Received a digital {user.receivedComforts[0].type}!</p>
                    <p className="text-xs opacity-70 italic mt-1">Sent with love just now.</p>
                 </div>
              </div>
           </div>
           <span className="absolute bottom-[-20%] right-[-10%] text-[10rem] opacity-10 rotate-12 group-hover:scale-110 transition-transform">💝</span>
        </section>
      )}

      {/* Mood Melodies Selection */}
      <section className="bg-white/50 p-6 rounded-[2.5rem] border border-pink-100/50">
        <h3 className="text-lg font-serif text-pink-500 mb-4 px-2 italic flex items-center gap-2">
          <span className="text-xl">🎶</span> Mood Melodies
        </h3>
        <div className="flex gap-3 overflow-x-auto pb-4 scrollbar-hide px-2">
          {MOODS.map((mood) => (
            <button
              key={mood.label}
              onClick={() => handleMoodSelect(mood)}
              className={`flex-shrink-0 flex flex-col items-center gap-2 p-4 rounded-3xl transition-all border-2 ${selectedMood === mood.label ? 'bg-pink-400 border-pink-400 text-white shadow-lg scale-105' : 'bg-white border-pink-50 text-pink-300 hover:border-pink-200'}`}
            >
              <span className="text-2xl">{mood.emoji}</span>
              <span className="text-[10px] font-bold uppercase tracking-tighter">{mood.label}</span>
            </button>
          ))}
        </div>
      </section>

      {/* Partner Reminders */}
      {activeReminders.length > 0 && (
        <section className="bg-indigo-50/50 p-6 rounded-[2.5rem] border border-indigo-100 shadow-sm">
          <h3 className="text-lg font-serif text-indigo-600 mb-4 flex items-center gap-2 px-2">
            <span className="text-xl">💝</span> From {user.partnerName}
          </h3>
          <div className="space-y-3">
            {activeReminders.map(reminder => (
              <div key={reminder.id} className="flex items-center gap-4 bg-white/90 p-5 rounded-3xl shadow-sm border border-indigo-50 hover:scale-[1.02] transition-transform">
                <div className="w-10 h-10 bg-indigo-100 rounded-full flex items-center justify-center text-xl">💌</div>
                <div>
                  <p className="text-base font-serif italic text-indigo-900 leading-tight">{reminder.text}</p>
                  <p className="text-[9px] text-indigo-400 font-bold uppercase tracking-widest mt-1">{reminder.time}</p>
                </div>
              </div>
            ))}
          </div>
        </section>
      )}

      {/* Main Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {/* Blooming Water Tracker */}
        <div className="bg-white p-8 rounded-[3rem] shadow-sm border border-pink-50 flex flex-col items-center justify-center text-center group">
          <h3 className="text-xl font-serif text-pink-500 mb-6 flex items-center gap-2 italic">
            <span className="text-2xl">💧</span> Hydration Bloom
          </h3>
          <div className="relative w-32 h-32 mb-6">
            <div className="absolute inset-0 border-4 border-pink-50 rounded-full"></div>
            <div 
              className="absolute inset-0 border-4 border-pink-400 rounded-full transition-all duration-1000 ease-out" 
              style={{ clipPath: `inset(${100 - waterPercentage}% 0 0 0)` }}
            ></div>
            <div className="absolute inset-0 flex flex-col items-center justify-center">
              <span className="text-3xl animate-pulse">🌸</span>
              <span className="text-[10px] font-bold text-pink-400 mt-1 uppercase">{waterPercentage.toFixed(0)}%</span>
            </div>
          </div>
          <div className="flex gap-3">
            <button 
              onClick={() => setWaterIntake(Math.max(0, waterIntake - 1))}
              className="w-10 h-10 rounded-full bg-pink-50 text-pink-500 flex items-center justify-center shadow-sm hover:bg-pink-100"
            >
              -
            </button>
            <button 
              onClick={() => setWaterIntake(Math.min(waterGoal, waterIntake + 1))}
              className="px-6 h-10 rounded-full bg-pink-500 text-white font-bold text-[10px] uppercase tracking-widest shadow-md hover:scale-105 transition-transform"
            >
              Add Drop
            </button>
            <button 
              onClick={() => setWaterIntake(waterGoal)}
              className="w-10 h-10 rounded-full bg-pink-50 text-pink-500 flex items-center justify-center shadow-sm hover:bg-pink-100"
            >
              ✨
            </button>
          </div>
        </div>

        {/* Dynamic Mini View (Cycle or Pregnancy) */}
        <div className="bg-white p-8 rounded-[3rem] shadow-sm border border-pink-50 flex flex-col justify-between">
          {user.isPregnancyMode ? (
            <div className="space-y-4">
              <h3 className="text-xl font-serif text-indigo-500 mb-2 flex items-center gap-2 italic">
                <span className="text-2xl">👶</span> Little Sprout
              </h3>
              <div className="flex items-center gap-4 bg-indigo-50/50 p-4 rounded-3xl">
                <span className="text-4xl">{currentBaby.fruit}</span>
                <div>
                  <p className="text-lg font-serif italic text-indigo-600">Week {weeks}</p>
                  <p className="text-[10px] font-bold text-indigo-400 uppercase tracking-widest">Size of a {currentBaby.size}</p>
                </div>
              </div>
              <p className="text-[10px] text-indigo-300 italic px-2">Your baby is developing tiny fingers today! ✨</p>
            </div>
          ) : (
            <div>
              <h3 className="text-xl font-serif text-pink-500 mb-6 flex items-center gap-2 italic">
                <span className="text-2xl">🌙</span> Divine Rhythm
              </h3>
              <div className="space-y-4">
                <div className="flex items-center justify-between bg-pink-50/50 p-4 rounded-2xl">
                  <span className="text-xs font-bold text-pink-400 uppercase">Phase</span>
                  <span className="text-lg font-serif italic text-pink-600">Follicular Bloom</span>
                </div>
                <div className="flex items-center justify-between bg-teal-50/50 p-4 rounded-2xl">
                  <span className="text-xs font-bold text-teal-400 uppercase">Ovulation In</span>
                  <span className="text-lg font-serif italic text-teal-600">6 Beautiful Days</span>
                </div>
              </div>
            </div>
          )}
          <button className={`mt-8 w-full py-4 rounded-3xl text-[10px] font-bold uppercase tracking-widest shadow-lg hover:scale-[1.02] transition-transform ${user.isPregnancyMode ? 'bg-indigo-500 text-white shadow-indigo-100' : 'bg-gradient-to-r from-pink-400 to-rose-400 text-white shadow-pink-100'}`}>
            {user.isPregnancyMode ? "Baby Journal" : "Log Your Feelings"}
          </button>
        </div>
      </div>

      {/* Featured Music Player */}
      <section className="bg-white p-8 rounded-[3rem] shadow-sm border border-pink-50 overflow-hidden relative group">
        <div className="flex flex-col md:flex-row items-center gap-8">
          <div className="relative w-40 h-40 flex-shrink-0">
            <div className={`absolute inset-0 bg-gradient-to-br from-pink-200 to-rose-300 rounded-full shadow-2xl transition-all duration-1000 ${isMusicPlaying ? 'rotate-[360deg] animate-[spin_12s_linear_infinite]' : ''}`}>
               <div className="absolute inset-4 bg-white/30 backdrop-blur-sm rounded-full border border-white/40 flex items-center justify-center text-6xl">
                 {currentSong.coverEmoji}
               </div>
            </div>
            <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-4 h-4 bg-white rounded-full shadow-inner z-10"></div>
          </div>

          <div className="flex-1 text-center md:text-left space-y-2">
            <p className="text-[10px] font-bold text-pink-300 uppercase tracking-widest mb-1 flex items-center justify-center md:justify-start gap-2">
              <span className="w-4 h-[1px] bg-pink-100"></span> Now Serenading <span className="w-4 h-[1px] bg-pink-100"></span>
            </p>
            <h3 className="text-3xl font-serif text-pink-600 italic leading-tight">{currentSong.title}</h3>
            <p className="text-sm text-pink-400 font-bold uppercase tracking-widest mb-6">{currentSong.artist}</p>

            <div className="flex items-center justify-center md:justify-start gap-6 pt-4">
              <button onClick={prevSong} className="text-3xl text-pink-200 hover:text-pink-400 transition-colors">⏮</button>
              <button 
                onClick={toggleMusic}
                className="w-14 h-14 bg-pink-500 text-white rounded-full flex items-center justify-center shadow-xl shadow-pink-200 hover:scale-110 active:scale-95 transition-all text-xl"
              >
                {isMusicPlaying ? '⏸' : '▶'}
