        />;
      case 'diary':
        return <Diary entries={diaryEntries} setEntries={setDiaryEntries} user={user} />;
      case 'selfcare':
        return <SelfCare tasks={selfCareTasks} setTasks={setSelfCareTasks} />;
      case 'settings':
        return <Settings />;
      default:
        return <Dashboard user={user} symptoms={symptoms} waterIntake={waterIntake} setWaterIntake={setWaterIntake} waterGoal={waterGoal} reminders={reminders} currentSongIndex={currentSongIndex} isMusicPlaying={isMusicPlaying} toggleMusic={toggleMusic} nextSong={nextSong} prevSong={prevSong} setCurrentSongIndex={setCurrentSongIndex} />;
    }
  };

  const currentTrack = fullLibrary[currentSongIndex];

  return (
    <div className={`min-h-screen pb-28 ${currentThemeData.bg} selection:bg-pink-100 transition-colors duration-500`}>
      <audio 
        ref={audioRef}
        src={currentTrack?.source === 'internal' ? currentTrack.url : undefined} 
        onEnded={nextSong}
        loop={false}
      />

      <header className="px-6 pt-10 pb-6 flex justify-between items-center bg-white/80 backdrop-blur-md shadow-sm sticky top-0 z-[60] border-b border-pink-50">
        <div className="cursor-pointer" onClick={() => setActiveTab('dashboard')}>
          <h1 className={`text-3xl font-serif italic ${themeClass}`}>Lumina</h1>
          <div className="flex gap-1 mt-1">
            {(Object.keys(THEMES) as AppTheme[]).map(t => (
              <button 
                key={t}
                onClick={(e) => { e.stopPropagation(); updateTheme(t); }}
                className={`w-3 h-3 rounded-full border border-white shadow-sm transition-transform hover:scale-125 ${t === 'rose' ? 'bg-pink-400' : t === 'lavender' ? 'bg-purple-400' : t === 'mint' ? 'bg-teal-400' : 'bg-orange-400'} ${user.theme === t ? 'ring-2 ring-offset-2 ring-gray-300' : ''}`}
              />
            ))}
          </div>
        </div>

        <div className="flex items-center gap-4">
          {!user.isPartner && (
            <button 
              onClick={togglePregnancy}
              className={`text-[9px] font-bold px-4 py-1.5 rounded-full border transition-all ${user.isPregnancyMode ? 'bg-indigo-500 text-white border-indigo-500 shadow-md' : 'bg-white text-gray-400 border-gray-200'}`}
            >
              {user.isPregnancyMode ? 'PREGNANCY MODE' : 'OFF'}
            </button>
          )}

          <div className="flex items-center gap-2 bg-pink-50/50 px-3 py-1.5 rounded-full border border-pink-100/50">
            <button 
              onClick={() => {
                if (currentTrack?.source !== 'internal') {
                  window.open(currentTrack.url, '_blank');
                } else {
                  toggleMusic();
                }
              }} 
              className="text-xs"
            >
              {currentTrack?.source !== 'internal' ? '↗' : (isMusicPlaying ? '⏸️' : '▶️')}
            </button>
            <input 
              type="range" min="0" max="1" step="0.01" value={volume} 
              onChange={(e) => setVolume(parseFloat(e.target.value))}
              className="w-10 h-1 accent-pink-400"
            />
          </div>

          <button onClick={() => setActiveTab('settings')} className="p-2 text-gray-400 hover:text-pink-400 transition-colors">
            ⚙️
          </button>
        </div>
      </header>

      <main className="max-w-4xl mx-auto px-4 mt-8 pb-10">
        {renderContent()}
      </main>

      {!user.isPartner && (
        <nav className="fixed bottom-0 left-0 right-0 bg-white/95 backdrop-blur-2xl border-t border-pink-50 flex justify-around items-center py-5 px-2 shadow-[0_-15px_40px_rgba(244,114,182,0.08)] z-50 rounded-t-[2.5rem]">
          <NavItem icon="🏠" label="Home" active={activeTab === 'dashboard'} onClick={() => setActiveTab('dashboard')} theme={user.theme} />
          <NavItem icon={user.isPregnancyMode ? "👶" : "🌸"} label={user.isPregnancyMode ? "Baby" : "Cycle"} active={activeTab === 'cycle'} onClick={() => setActiveTab('cycle')} theme={user.theme} />
          <NavItem icon="📖" label="Pedia" active={activeTab === 'pedia'} onClick={() => setActiveTab('pedia')} theme={user.theme} />
          <NavItem icon="🎓" label="Learn" active={activeTab === 'edu'} onClick={() => setActiveTab('edu')} theme={user.theme} />
          <NavItem icon="💧" label="Water" active={activeTab === 'water'} onClick={() => setActiveTab('water')} theme={user.theme} />
          <NavItem icon="📔" label="Diary" active={activeTab === 'diary'} onClick={() => setActiveTab('diary')} theme={user.theme} />
          <NavItem icon="✨" label="Self" active={activeTab === 'selfcare'} onClick={() => setActiveTab('selfcare')} theme={user.theme} />
        </nav>
      )}
    </div>
  );
};

const NavItem: React.FC<{ icon: string, label: string, active: boolean, onClick: () => void, theme: AppTheme }> = ({ icon, label, active, onClick, theme }) => {
  const color = THEMES[theme].primary;
  return (
    <button 
      onClick={onClick}
      className={`flex flex-col items-center gap-1.5 transition-all ${active ? `text-${color} scale-110 font-bold drop-shadow-sm` : 'text-gray-400 grayscale'}`}
    >
      <span className="text-2xl">{icon}</span>
      <span className="text-[8px] uppercase tracking-tighter font-black">{label}</span>
      {active && <div className={`w-1 h-1 rounded-full bg-pink-400 mt-0.5`}></div>}
    </button>
  );
};

export default App;

import React, { useState } from 'react';
import { User, TemperatureLog } from '../types';

interface TemperatureTrackerProps {
  user: User;
  logs: TemperatureLog[];
  setLogs: React.Dispatch<React.SetStateAction<TemperatureLog[]>>;
  onUpdateUnit: (unit: 'C' | 'F') => void;
}

const TemperatureTracker: React.FC<TemperatureTrackerProps> = ({ user, logs, setLogs, onUpdateUnit }) => {
  const [inputValue, setInputValue] = useState('');
  const today = new Date().toDateString();
  const todayLog = logs.find(log => log.date === today);
  const unit = user.tempUnit || 'C';

  // Scales: C: 35.5 - 38.0 | F: 96.0 - 100.0
  const minTemp = unit === 'C' ? 35.5 : 96.0;
  const maxTemp = unit === 'C' ? 38.0 : 100.4;
  const range = maxTemp - minTemp;

  const handleAddLog = () => {
    const val = parseFloat(inputValue);
    if (isNaN(val)) return;

    const newLog: TemperatureLog = {
      id: Math.random().toString(),
      date: today,
      value: val,
      unit
    };

    setLogs(prev => [newLog, ...prev.filter(l => l.date !== today)]);
    setInputValue('');
  };

  const getPercentage = (val: number) => {
    return Math.max(0, Math.min(100, ((val - minTemp) / range) * 100));
  };

  return (
    <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-pink-50 space-y-8 animate-fadeIn">
      <div className="flex justify-between items-center">
        <h3 className="text-xl font-serif text-pink-500 flex items-center gap-2 italic">
          <span className="text-2xl">🌡️</span> Basal Temperature
        </h3>
        <div className="flex bg-pink-50/50 p-1 rounded-xl border border-pink-100">
          <button 
            onClick={() => onUpdateUnit('C')}
            className={`px-3 py-1 rounded-lg text-[10px] font-bold transition-all ${unit === 'C' ? 'bg-white text-pink-500 shadow-sm' : 'text-pink-300'}`}
          >
            °C
          </button>
          <button 
            onClick={() => onUpdateUnit('F')}
            className={`px-3 py-1 rounded-lg text-[10px] font-bold transition-all ${unit === 'F' ? 'bg-white text-pink-500 shadow-sm' : 'text-pink-300'}`}
          >
            °F
          </button>
        </div>
      </div>

      <div className="flex flex-col md:flex-row gap-8 items-center">
        {/* Thermometer Scale UI */}
        <div className="relative h-64 w-12 bg-pink-50/50 rounded-full border border-pink-100 overflow-hidden flex flex-col-reverse group">
          <div 
            className="bg-gradient-to-t from-pink-400 to-rose-300 w-full transition-all duration-1000 ease-out flex items-start justify-center relative"
            style={{ height: `${todayLog ? getPercentage(todayLog.value) : 0}%` }}
          >
            <div className="w-full h-1 bg-white/50 blur-[1px]"></div>
            {todayLog && (
              <div className="absolute -top-8 bg-pink-500 text-white text-[10px] px-2 py-1 rounded-full font-bold shadow-lg whitespace-nowrap">
                {todayLog.value}°{unit}
              </div>
            )}
          </div>
          {/* Ticks */}
          <div className="absolute inset-0 flex flex-col justify-between py-6 px-1 opacity-20 pointer-events-none">
            {[...Array(6)].map((_, i) => <div key={i} className="w-full h-[1px] bg-pink-300"></div>)}
          </div>
        </div>

        <div className="flex-1 space-y-6 w-full">
          <div className="space-y-4">
            <p className="text-[10px] font-bold text-pink-300 uppercase tracking-widest ml-2">Log Today's Reading</p>
            <div className="flex gap-3">
              <input 
                type="number" 
                step="0.1"
                value={inputValue}
                onChange={(e) => setInputValue(e.target.value)}
                placeholder={unit === 'C' ? "36.5" : "97.7"}
                className="flex-1 px-6 py-4 bg-pink-50/30 border border-pink-50 rounded-2xl focus:ring-4 focus:ring-pink-100 outline-none text-pink-700 font-serif italic text-lg shadow-sm"
              />
              <button 
                onClick={handleAddLog}
                className="px-8 py-4 bg-pink-400 text-white rounded-2xl font-bold uppercase text-[10px] tracking-widest shadow-lg shadow-pink-100 hover:scale-105 active:scale-95 transition-all"
              >
                Log
              </button>
            </div>
          </div>

          <div className="bg-rose-50/50 p-6 rounded-3xl border border-rose-100">
             <div className="flex items-center gap-3 mb-2">
                <span className="text-xl">✨</span>
                <h4 className="text-[10px] font-bold text-rose-400 uppercase tracking-widest leading-none">Why track BBT?</h4>
             </div>
             <p className="text-xs text-rose-600 font-serif italic leading-relaxed">
               Your resting temperature rises slightly after ovulation. Tracking this helps identify your fertile window with high precision. Best measured right after waking up!
             </p>
          </div>
        </div>
      </div>

      {/* History List */}
      <div className="pt-4 border-t border-pink-50">
        <h4 className="text-[10px] font-bold text-pink-300 uppercase tracking-widest mb-4 ml-2">Recent Readings</h4>
        <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
          {logs.slice(0, 4).map(log => (
            <div key={log.id} className="p-3 bg-pink-50/20 rounded-2xl border border-pink-50 flex flex-col items-center">
              <span className="text-[9px] text-pink-300 font-bold uppercase">{log.date.split(' ').slice(1, 3).join(' ')}</span>
              <span className="text-base font-serif italic text-pink-600 font-bold">{log.value}°{log.unit}</span>
            </div>
          ))}
          {logs.length === 0 && <p className="col-span-4 text-center text-xs text-pink-200 italic py-4">No readings yet, princess...</p>}
        </div>
      </div>
    </div>
  );
};

export default TemperatureTracker;

import React, { useState } from 'react';
import { User, Symptom, BirthControlLog, BirthControlConfig, TemperatureLog } from '../types';
import { SYMPTOMS } from '../constants';
import TemperatureTracker from './TemperatureTracker';

interface PeriodTrackerProps {
  user: User;
  symptoms: Symptom[];
  setSymptoms: React.Dispatch<React.SetStateAction<Symptom[]>>;
  bcLogs: BirthControlLog[];
  setBcLogs: React.Dispatch<React.SetStateAction<BirthControlLog[]>>;
  onUpdateBCConfig: (config: BirthControlConfig) => void;
  tempLogs: TemperatureLog[];
  setTempLogs: React.Dispatch<React.SetStateAction<TemperatureLog[]>>;
  onUpdateTempUnit: (unit: 'C' | 'F') => void;
}

const PeriodTracker: React.FC<PeriodTrackerProps> = ({ 
  user, 
  symptoms, 
  setSymptoms, 
  bcLogs, 
  setBcLogs,
  onUpdateBCConfig,
  tempLogs,
  setTempLogs,
  onUpdateTempUnit
}) => {
  const [isSettingBC, setIsSettingBC] = useState(false);
  const [bcMethod, setBcMethod] = useState(user.birthControlConfig?.method || 'Pill');
  const [bcFrequency, setBcFrequency] = useState<BirthControlConfig['frequency']>(user.birthControlConfig?.frequency || 'daily');
  const [bcTime, setBcTime] = useState(user.birthControlConfig?.reminderTime || '09:00');

  const today = new Date().toDateString();
  const isTakenToday = bcLogs.some(log => log.date === today && log.taken);

  const toggleSymptom = (type: Symptom['type']) => {
    const existing = symptoms.find(s => s.type === type && s.date === today);
    if (existing) {
      setSymptoms(symptoms.filter(s => s !== existing));
    } else {
      setSymptoms([...symptoms, {
        id: Math.random().toString(),
        date: today,
        type,
        intensity: 2
      }]);
    }
  };

  const handleLogIntake = () => {
    if (isTakenToday) {
      setBcLogs(bcLogs.filter(log => log.date !== today));
    } else {
      setBcLogs([...bcLogs, { date: today, taken: true }]);
    }
  };

  const saveBCConfig = () => {
    onUpdateBCConfig({
      method: bcMethod,
      frequency: bcFrequency,
      reminderTime: bcTime,
      enabled: true
    });
    setIsSettingBC(false);
  };

  const getDayStatus = (day: number) => {
    const pStart = 1;
    const pEnd = user.periodLength || 5;
    const ovulationDay = (user.cycleLength || 28) - 14;
    const fertileStart = ovulationDay - 4;
    const fertileEnd = ovulationDay + 1;

    if (day >= pStart && day <= pEnd) return 'period';
    if (day === ovulationDay) return 'ovulation';
    if (day >= fertileStart && day <= fertileEnd) return 'fertile';
    return 'none';
  };

  const dayStyles = {
    period: 'bg-pink-400 text-white font-bold shadow-md shadow-pink-100',
    ovulation: 'bg-teal-400 text-white font-bold shadow-md shadow-teal-100 ring-2 ring-teal-200',
    fertile: 'bg-teal-50 text-teal-600 font-medium border border-teal-100',
    none: 'hover:bg-pink-50 text-gray-400'
  };

  return (
    <div className="space-y-8 animate-fadeIn pb-12">
      <header className="text-center">
        <h2 className="text-3xl font-serif text-pink-500 italic">Cycle Sanctuary</h2>
        <p className="text-sm text-pink-300 italic">Your body, your rhythm, your power</p>
      </header>

      {/* Birth Control Tracker */}
      <section className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-pink-50 relative overflow-hidden">
        <div className="flex justify-between items-center mb-6">
          <h3 className="text-xl font-serif text-pink-500 flex items-center gap-2 italic">
            <span className="text-2xl">💊</span> Birth Control
          </h3>
          <button 
            onClick={() => setIsSettingBC(!isSettingBC)}
            className="text-[10px] font-bold text-pink-300 uppercase hover:text-pink-500 transition-colors"
          >
            {isSettingBC ? 'Close' : 'Configure'}
          </button>
        </div>

        {isSettingBC ? (
          <div className="space-y-6 animate-fadeIn">
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <label className="text-[10px] font-bold text-pink-300 uppercase ml-2">Method</label>
                <select 
                  value={bcMethod}
                  onChange={(e) => setBcMethod(e.target.value)}
                  className="w-full bg-pink-50/50 p-3 rounded-2xl outline-none text-pink-600 font-bold text-sm border border-transparent focus:border-pink-200"
                >
                  {['Pill', 'Patch', 'Ring', 'Injection', 'IUD', 'Implant'].map(m => (
                    <option key={m} value={m}>{m}</option>
                  ))}
                </select>
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-bold text-pink-300 uppercase ml-2">Frequency</label>
                <select 
                  value={bcFrequency}
                  onChange={(e) => setBcFrequency(e.target.value as any)}
                  className="w-full bg-pink-50/50 p-3 rounded-2xl outline-none text-pink-600 font-bold text-sm border border-transparent focus:border-pink-200"
                >
                  <option value="daily">Daily</option>
                  <option value="weekly">Weekly</option>
                  <option value="monthly">Monthly</option>
                </select>
              </div>
            </div>
            <div className="space-y-2">
              <label className="text-[10px] font-bold text-pink-300 uppercase ml-2">Reminder Time</label>
              <input 
                type="time" 
                value={bcTime}
                onChange={(e) => setBcTime(e.target.value)}
                className="w-full bg-pink-50/50 p-3 rounded-2xl outline-none text-pink-600 font-bold text-sm border border-transparent focus:border-pink-200"
              />
            </div>
            <button 
              onClick={saveBCConfig}
              className="w-full py-4 bg-pink-400 text-white rounded-2xl font-bold uppercase tracking-widest text-[10px] shadow-lg shadow-pink-100"
            >
              Save Settings
            </button>
          </div>
        ) : (
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-4">
              <div className={`w-14 h-14 rounded-full flex items-center justify-center text-2xl transition-all shadow-inner ${isTakenToday ? 'bg-pink-400 text-white' : 'bg-pink-50 text-pink-200'}`}>
                {isTakenToday ? '✨' : '💊'}
              </div>
              <div>
                <p className="font-serif italic text-lg text-pink-600">
                  {user.birthControlConfig?.enabled ? user.birthControlConfig.method : 'Track your method'}
                </p>
                <p className="text-[10px] font-bold text-pink-300 uppercase tracking-widest">
                  {user.birthControlConfig?.enabled ? `${user.birthControlConfig.frequency} • ${user.birthControlConfig.reminderTime}` : 'Tap configure to start'}
                </p>
              </div>
            </div>
            <button 
              onClick={handleLogIntake}
              className={`px-6 py-3 rounded-full font-bold text-[10px] uppercase tracking-widest transition-all ${isTakenToday ? 'bg-pink-50 text-pink-400' : 'bg-pink-400 text-white shadow-lg shadow-pink-100 hover:scale-105 active:scale-95'}`}
            >
              {isTakenToday ? 'Taken Today' : 'Log Intake'}
            </button>
          </div>
        )}
      </section>

      {/* Temperature Tracker Component */}
      <TemperatureTracker 
        user={user} 
        logs={tempLogs} 
        setLogs={setTempLogs} 
        onUpdateUnit={onUpdateTempUnit} 
      />

      {/* Calendar Preview */}
      <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-pink-50">
        <div className="flex justify-between items-center mb-6 px-2">
           <h3 className="font-serif text-xl text-pink-600 italic">March 2024</h3>
           <div className="flex gap-2">
              <button className="w-8 h-8 rounded-full bg-pink-50 text-pink-400 flex items-center justify-center hover:bg-pink-100 transition-colors">←</button>
              <button className="w-8 h-8 rounded-full bg-pink-50 text-pink-400 flex items-center justify-center hover:bg-pink-100 transition-colors">→</button>
           </div>
        </div>

        <div className="grid grid-cols-7 gap-2 text-center text-[10px] font-bold text-pink-300 uppercase mb-4">
          <span>Mon</span><span>Tue</span><span>Wed</span><span>Thu</span><span>Fri</span><span>Sat</span><span>Sun</span>
        </div>

        <div className="grid grid-cols-7 gap-3">
          {[...Array(2)].map((_, i) => <div key={`empty-${i}`} />)}

          {[...Array(31)].map((_, i) => {
            const dayNum = i + 1;
            const status = getDayStatus(dayNum);

            return (
              <div 
                key={i} 
                className={`relative aspect-square flex items-center justify-center rounded-2xl text-sm transition-all cursor-pointer ${dayStyles[status]}`}
              >
                {dayNum}
                {status === 'ovulation' && (
                  <span className="absolute -top-1 -right-1 text-[10px]">✨</span>
                )}
              </div>
            );
          })}
        </div>

        {/* Dynamic Legend */}
        <div className="mt-10 grid grid-cols-2 gap-4">
           <div className="flex items-center gap-3 p-3 bg-pink-50/50 rounded-2xl">
              <div className="w-4 h-4 bg-pink-400 rounded-lg shadow-sm"></div>
              <div className="flex flex-col">
                <span className="text-[10px] text-pink-500 uppercase font-black leading-none">Period</span>
                <span className="text-[9px] text-pink-300 italic">Heavy flow expected</span>
              </div>
           </div>
           <div className="flex items-center gap-3 p-3 bg-teal-50/50 rounded-2xl">
              <div className="w-4 h-4 bg-teal-400 rounded-lg shadow-sm"></div>
              <div className="flex flex-col">
                <span className="text-[10px] text-teal-600 uppercase font-black leading-none">Ovulation</span>
                <span className="text-[9px] text-teal-400 italic">Peak fertility</span>
              </div>
           </div>
        </div>
      </div>

      <section>
        <h3 className="text-xl font-serif text-pink-500 mb-4 px-2">How are you feeling today?</h3>
        <div className="grid grid-cols-3 gap-4">
          {SYMPTOMS.map((s) => {
             const isActive = symptoms.some(item => item.type === s.id && item.date === today);
             return (
               <button 
                 key={s.id}
                 onClick={() => toggleSymptom(s.id as any)}
                 className={`group flex flex-col items-center gap-3 p-6 rounded-[2.5rem] transition-all border-2 relative overflow-hidden ${isActive ? 'bg-pink-100 border-pink-300 shadow-lg shadow-pink-100 scale-105' : 'bg-white border-pink-50 hover:border-pink-200'}`}
               >
                 {isActive && (
                   <div className="absolute top-0 right-0 p-2">
                     <div className="w-2 h-2 bg-pink-400 rounded-full animate-ping"></div>
                   </div>
                 )}
                 <span className={`text-4xl transition-transform group-hover:scale-110 ${isActive ? 'animate-bounce' : ''}`}>{s.emoji}</span>
                 <span className={`text-[10px] font-bold uppercase tracking-tighter ${isActive ? 'text-pink-600' : 'text-pink-300'}`}>{s.label}</span>
               </button>
             );
          })}
        </div>
      </section>

      <div className="p-8 bg-gradient-to-br from-pink-500 to-rose-400 rounded-[2.5rem] text-white shadow-xl shadow-pink-200 relative overflow-hidden">
        <div className="relative z-10">
          <p className="text-xs font-bold uppercase tracking-widest opacity-80 mb-2">Cycle Wisdom</p>
          <p className="text-xl font-serif italic leading-relaxed">
            "Your body is preparing for its most fertile time. Stay hydrated and prioritize gentle movement to support your energy levels."
          </p>
        </div>
        <span className="absolute -bottom-10 -right-10 text-[12rem] opacity-10">✨</span>
      </div>
    </div>
  );
};

