import React, { useState, useEffect, useRef } from 'react';
import { User, Symptom, DiaryEntry, SelfCareTask, AppTheme, Reminder, BirthControlLog, Song, TemperatureLog } from './types';
import Auth from './components/Auth';
import Dashboard from './components/Dashboard';
import PeriodTracker from './components/PeriodTracker';
import SelfCare from './components/SelfCare';
import YogaTutorials from './components/YogaTutorials';
import Diary from './components/Diary';
import PartnerMode from './components/PartnerMode';
import WaterTracker from './components/WaterTracker';
import Education from './components/Education';
import Cyclepedia from './components/Cyclepedia';
import Wellness from './components/Wellness';
import PregnancyTracker from './components/PregnancyTracker';
import Settings from './components/Settings';
import MusicRoom from './components/MusicRoom';
import { playWelcomeVoice } from './services/gemini';
import { THEMES, SONGS } from './constants';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [symptoms, setSymptoms] = useState<Symptom[]>([]);
  const [diaryEntries, setDiaryEntries] = useState<DiaryEntry[]>([]);
  const [waterIntake, setWaterIntake] = useState(0);
  const [waterGoal, setWaterGoal] = useState(8);
  const [isMusicPlaying, setIsMusicPlaying] = useState(false);
  const [currentSongIndex, setCurrentSongIndex] = useState(0);
  const [volume, setVolume] = useState(0.3);
  const [reminders, setReminders] = useState<Reminder[]>([]);
  const [bcLogs, setBcLogs] = useState<BirthControlLog[]>([]);
  const [tempLogs, setTempLogs] = useState<TemperatureLog[]>([]);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  const [selfCareTasks, setSelfCareTasks] = useState<SelfCareTask[]>([
    { id: '1', task: 'Drink warm tea ritual', completed: false },
    { id: '2', task: 'Facial massage', completed: false },
    { id: '3', task: 'Meditation for 5 mins', completed: false },
    { id: '4', task: 'Gentle yoga stretch', completed: false },
  ]);

  useEffect(() => {
    if (user) {
      const stored = localStorage.getItem('lumina_users');
      if (stored) {
        const users = JSON.parse(stored);
        const idx = users.findIndex((u: any) => u.email === user.email);
        if (idx !== -1) {
          users[idx] = { ...users[idx], ...user };
          localStorage.setItem('lumina_users', JSON.stringify(users));
        }
      }
    }
  }, [user]);

  const handleLogin = (userData: User) => {
    const fullUser: User = {
      ...userData,
      theme: userData.theme || 'rose',
      tempUnit: userData.tempUnit || 'C',
      isPregnancyMode: userData.isPregnancyMode || false,
      diaryPin: userData.diaryPin || '1234',
      favoriteSongs: userData.favoriteSongs || [],
      customSongs: userData.customSongs || [],
      birthControlConfig: userData.birthControlConfig || {
        method: 'Pill',
        frequency: 'daily',
        reminderTime: '09:00',
        enabled: false
      }
    };
    setUser(fullUser);
    playWelcomeVoice(fullUser.name);
    setIsMusicPlaying(true);
  };

  const updateTheme = (newTheme: AppTheme) => {
    if (user) {
      setUser({ ...user, theme: newTheme });
    }
  };

  const updateTempUnit = (unit: 'C' | 'F') => {
    if (user) {
      setUser({ ...user, tempUnit: unit });
    }
  };

  const toggleFavoriteSong = (songId: string) => {
    if (!user) return;
    const currentFavs = user.favoriteSongs || [];
    const newFavs = currentFavs.includes(songId) 
      ? currentFavs.filter(id => id !== songId) 
      : [...currentFavs, songId];
    setUser({ ...user, favoriteSongs: newFavs });
  };

  const addCustomSong = (song: Song) => {
    if (!user) return;
    const newCustoms = [...(user.customSongs || []), song];
    setUser({ ...user, customSongs: newCustoms });
  };

  const togglePregnancy = () => {
    if (user) {
      setUser({ 
        ...user, 
        isPregnancyMode: !user.isPregnancyMode,
        pregnancyStartDate: !user.isPregnancyMode ? new Date().toISOString() : undefined 
      });
    }
  };

  const updateBCConfig = (config: User['birthControlConfig']) => {
    if (user && config) {
      setUser({ ...user, birthControlConfig: config });
    }
  };

  const toggleMusic = () => {
    setIsMusicPlaying(!isMusicPlaying);
  };

  const fullLibrary = [...SONGS, ...(user?.customSongs || [])];

  const nextSong = () => {
    setCurrentSongIndex((prev) => (prev + 1) % fullLibrary.length);
  };

  const prevSong = () => {
    setCurrentSongIndex((prev) => (prev - 1 + fullLibrary.length) % fullLibrary.length);
  };

  useEffect(() => {
    if (audioRef.current) {
      const currentTrack = fullLibrary[currentSongIndex];
      if (currentTrack?.source === 'internal') {
        if (isMusicPlaying) {
          audioRef.current.play().catch(e => console.log("Playback interaction required", e));
        } else {
          audioRef.current.pause();
        }
      }
    }
  }, [isMusicPlaying, currentSongIndex, user?.customSongs]);

  useEffect(() => {
    if (audioRef.current) {
      audioRef.current.volume = volume;
    }
  }, [volume]);

  if (!user) {
    return <Auth onLogin={handleLogin} />;
  }

  const currentThemeData = THEMES[user.theme || 'rose'];
  const themeClass = `text-${currentThemeData.primary}`;

  const renderContent = () => {
    if (user.isPartner) {
      return <PartnerMode user={user} reminders={reminders} setReminders={setReminders} />;
    }

    switch (activeTab) {
      case 'dashboard':
        return (
          <Dashboard 
            user={user} 
            symptoms={symptoms} 
            waterIntake={waterIntake} 
            setWaterIntake={setWaterIntake} 
            waterGoal={waterGoal} 
            reminders={reminders} 
            currentSongIndex={currentSongIndex}
            isMusicPlaying={isMusicPlaying}
            toggleMusic={toggleMusic}
            nextSong={nextSong}
            prevSong={prevSong}
            setCurrentSongIndex={setCurrentSongIndex}
            onTabChange={setActiveTab}
          />
        );
      case 'cycle':
        return user.isPregnancyMode 
          ? <PregnancyTracker user={user} /> 
          : <PeriodTracker 
              user={user} 
              symptoms={symptoms} 
              setSymptoms={setSymptoms} 
              bcLogs={bcLogs} 
              setBcLogs={setBcLogs}
              onUpdateBCConfig={updateBCConfig}
              tempLogs={tempLogs}
              setTempLogs={setTempLogs}
              onUpdateTempUnit={updateTempUnit}
            />;
      case 'wellness':
        return <Wellness symptoms={symptoms} />;
      case 'pedia':
        return <Cyclepedia />;
      case 'edu':
        return <Education />;
      case 'water':
        return <WaterTracker waterIntake={waterIntake} setWaterIntake={setWaterIntake} waterGoal={waterGoal} setWaterGoal={setWaterGoal} />;
      case 'music':
        return <MusicRoom 
          user={user} 
          onToggleFavorite={toggleFavoriteSong} 
          currentSongIndex={currentSongIndex} 
          onSelectSong={setCurrentSongIndex} 
          isMusicPlaying={isMusicPlaying} 
          onTogglePlay={toggleMusic} 
          onAddCustomSong={addCustomSong}
        />;
      case 'diary':
        return <Diary entries={diaryEntries} setEntries={setDiaryEntries} user={user} />;
      case 'selfcare':
        return <SelfCare tasks={selfCareTasks} setTasks={setSelfCareTasks} />;
      case 'settings':
        return <Settings />;
      default:
        return <Dashboard user={user} symptoms={symptoms} waterIntake={waterIntake} setWaterIntake={setWaterIntake} waterGoal={waterGoal} reminders={reminders} currentSongIndex={currentSongIndex} isMusicPlaying={isMusicPlaying} toggleMusic={toggleMusic} nextSong={nextSong} prevSong={prevSong} setCurrentSongIndex={setCurrentSongIndex} onTabChange={setActiveTab} />;
    }
  };

  const currentTrack = fullLibrary[currentSongIndex];

  return (
    <div className={`min-h-screen pb-28 ${currentThemeData.bg} selection:bg-pink-100 transition-colors duration-500`}>
      <audio 
        ref={audioRef}
        src={currentTrack?.source === 'internal' ? currentTrack.url : undefined} 
        onEnded={nextSong}
        loop={false}
      />

      <header className="px-6 pt-10 pb-6 flex justify-between items-center bg-white/80 backdrop-blur-md shadow-sm sticky top-0 z-[60] border-b border-pink-50">
        <div className="cursor-pointer" onClick={() => setActiveTab('dashboard')}>
          <h1 className={`text-3xl font-serif italic ${themeClass}`}>Lumina</h1>
          <div className="flex gap-1 mt-1">
            {(Object.keys(THEMES) as AppTheme[]).map(t => (
              <button 
                key={t}
                onClick={(e) => { e.stopPropagation(); updateTheme(t); }}
                className={`w-3 h-3 rounded-full border border-white shadow-sm transition-transform hover:scale-125 ${t === 'rose' ? 'bg-pink-400' : t === 'lavender' ? 'bg-purple-400' : t === 'mint' ? 'bg-teal-400' : 'bg-orange-400'} ${user.theme === t ? 'ring-2 ring-offset-2 ring-gray-300' : ''}`}
              />
            ))}
          </div>
        </div>

        <div className="flex items-center gap-4">
          {!user.isPartner && (
            <button 
              onClick={togglePregnancy}
              className={`text-[9px] font-bold px-4 py-1.5 rounded-full border transition-all ${user.isPregnancyMode ? 'bg-indigo-500 text-white border-indigo-500 shadow-md' : 'bg-white text-gray-400 border-gray-200'}`}
            >
              {user.isPregnancyMode ? 'PREGNANCY MODE' : 'OFF'}
            </button>
          )}

          <div className="flex items-center gap-2 bg-pink-50/50 px-3 py-1.5 rounded-full border border-pink-100/50">
            <button 
              onClick={() => {
                if (currentTrack?.source !== 'internal') {
                  window.open(currentTrack.url, '_blank');
                } else {
                  toggleMusic();
                }
              }} 
              className="text-xs"
            >
              {currentTrack?.source !== 'internal' ? '↗' : (isMusicPlaying ? '⏸️' : '▶️')}
            </button>
            <input 
              type="range" min="0" max="1" step="0.01" value={volume} 
              onChange={(e) => setVolume(parseFloat(e.target.value))}
              className="w-10 h-1 accent-pink-400"
            />
          </div>

          <button onClick={() => setActiveTab('settings')} className="p-2 text-gray-400 hover:text-pink-400 transition-colors">
            ⚙️
          </button>
        </div>
      </header>

      <main className="max-w-4xl mx-auto px-4 mt-8 pb-10">
        {renderContent()}
      </main>

      {!user.isPartner && (
        <nav className="fixed bottom-0 left-0 right-0 bg-white/95 backdrop-blur-2xl border-t border-pink-50 flex justify-around items-center py-5 px-2 shadow-[0_-15px_40px_rgba(244,114,182,0.08)] z-50 rounded-t-[2.5rem]">
          <NavItem icon="🏠" label="Home" active={activeTab === 'dashboard'} onClick={() => setActiveTab('dashboard')} theme={user.theme} />
          <NavItem icon={user.isPregnancyMode ? "👶" : "🌸"} label={user.isPregnancyMode ? "Baby" : "Cycle"} active={activeTab === 'cycle'} onClick={() => setActiveTab('cycle')} theme={user.theme} />
          <NavItem icon="✨" label="Wellness" active={activeTab === 'wellness'} onClick={() => setActiveTab('wellness')} theme={user.theme} />
          <NavItem icon="📖" label="Pedia" active={activeTab === 'pedia'} onClick={() => setActiveTab('pedia')} theme={user.theme} />
          <NavItem icon="🎓" label="Learn" active={activeTab === 'edu'} onClick={() => setActiveTab('edu')} theme={user.theme} />
          <NavItem icon="💧" label="Water" active={activeTab === 'water'} onClick={() => setActiveTab('water')} theme={user.theme} />
          <NavItem icon="📔" label="Diary" active={activeTab === 'diary'} onClick={() => setActiveTab('diary')} theme={user.theme} />
          <NavItem icon="💆‍♀️" label="Self" active={activeTab === 'selfcare'} onClick={() => setActiveTab('selfcare')} theme={user.theme} />
        </nav>
      )}
    </div>
  );
};

const NavItem: React.FC<{ icon: string, label: string, active: boolean, onClick: () => void, theme: AppTheme }> = ({ icon, label, active, onClick, theme }) => {
  const color = THEMES[theme].primary;
  return (
    <button 
      onClick={onClick}
      className={`flex flex-col items-center gap-1.5 transition-all ${active ? `text-${color} scale-110 font-bold drop-shadow-sm` : 'text-gray-400 grayscale'}`}
    >
      <span className="text-2xl">{icon}</span>
      <span className="text-[8px] uppercase tracking-tighter font-black">{label}</span>
      {active && <div className={`w-1 h-1 rounded-full bg-pink-400 mt-0.5`}></div>}
    </button>
  );
};

export default App;

import React, { useEffect, useState } from 'react';
import { User, Symptom, Reminder } from '../types';
import { getDailyAffirmation } from '../services/gemini';
import { SONGS, MOODS, BABY_SIZES } from '../constants';

interface DashboardProps {
  user: User;
  symptoms: Symptom[];
  waterIntake: number;
  setWaterIntake: React.Dispatch<React.SetStateAction<number>>;
  waterGoal: number;
  reminders: Reminder[];
  currentSongIndex: number;
  isMusicPlaying: boolean;
  toggleMusic: () => void;
  nextSong: () => void;
  prevSong: () => void;
  setCurrentSongIndex: (index: number) => void;
  onTabChange?: (tab: string) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ 
  user, 
  waterIntake, 
  setWaterIntake, 
  waterGoal, 
  reminders,
  currentSongIndex,
  isMusicPlaying,
  toggleMusic,
  nextSong,
  prevSong,
  setCurrentSongIndex,
  onTabChange
}) => {
  const [affirmation, setAffirmation] = useState("Loading your daily inspiration...");
  const [selectedMood, setSelectedMood] = useState('Happy');

  useEffect(() => {
    getDailyAffirmation().then(setAffirmation);
  }, []);

  const handleMoodSelect = (mood: typeof MOODS[0]) => {
    setSelectedMood(mood.label);
    const moodSong = SONGS.find(s => s.tags.includes(mood.songTag));
    if (moodSong) {
      const idx = SONGS.indexOf(moodSong);
      if (idx !== -1) setCurrentSongIndex(idx);
    }
  };

  const activeReminders = reminders.filter(r => !r.isCompleted);
  const currentSong = SONGS[currentSongIndex];
  const waterPercentage = Math.min((waterIntake / waterGoal) * 100, 100);

  // Pregnancy calculations
  const startDate = user.pregnancyStartDate ? new Date(user.pregnancyStartDate) : new Date();
  const diffTime = Math.abs(new Date().getTime() - startDate.getTime());
  const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
  const weeks = Math.min(40, Math.floor(diffDays / 7) + 1);
  const currentBaby = BABY_SIZES.find(b => b.week === Math.floor(weeks / 4) * 4) || BABY_SIZES[0];

  return (
    <div className="space-y-8 animate-fadeIn pb-12">
      {/* Hero Welcome */}
      <section className="relative overflow-hidden bg-gradient-to-br from-pink-100 via-rose-50 to-pink-100 p-8 rounded-[3rem] shadow-[0_10px_40px_rgba(244,114,182,0.1)] text-pink-600 border border-white/50">
        <div className="relative z-10">
          <div className="flex items-center gap-3 mb-2">
            <h2 className="text-4xl font-serif italic">Hello, {user.name}</h2>
            <span className="text-3xl animate-bounce">✨</span>
          </div>
          <p className="text-sm opacity-80 mb-6 italic font-medium">
            {user.isPregnancyMode ? "Nurturing a tiny soul today." : "Your sanctuary is blooming beautifully today."}
          </p>

          <div className="bg-white/60 backdrop-blur-md p-6 rounded-3xl border border-white/60 shadow-sm">
            <p className="text-[10px] font-bold uppercase tracking-widest text-pink-400 mb-2">Daily Whisper</p>
            <p className="text-xl font-serif italic text-pink-700 leading-relaxed">"{affirmation}"</p>
          </div>
        </div>
        <div className="absolute top-0 right-0 -translate-y-6 translate-x-6">
           <span className="text-[12rem] opacity-10 rotate-12">🌸</span>
        </div>
        <div className="absolute bottom-0 left-0 -translate-x-6 translate-y-6">
           <span className="text-[8rem] opacity-5 -rotate-12">🎀</span>
        </div>
      </section>

      {/* Received Comforts (Partner Interactions) */}
      {user.receivedComforts && user.receivedComforts.length > 0 && (
        <section className="bg-gradient-to-r from-pink-400 to-rose-400 p-8 rounded-[3rem] text-white shadow-xl animate-fadeIn relative overflow-hidden group">
           <div className="relative z-10">
              <h3 className="text-xs font-bold uppercase tracking-[0.3em] opacity-80 mb-4 flex items-center gap-2">
                 <span className="animate-ping w-2 h-2 bg-white rounded-full"></span> 
                 A gift from {user.partnerName}
              </h3>
              <div className="flex items-center gap-6">
                 <div className="w-20 h-20 bg-white/20 backdrop-blur-md rounded-full flex items-center justify-center text-5xl shadow-inner border border-white/30">
                    {user.receivedComforts[0].type === 'hug' ? '🫂' : 
                     user.receivedComforts[0].type === 'tea' ? '🍵' : 
                     user.receivedComforts[0].type === 'flower' ? '💐' : 
                     user.receivedComforts[0].type === 'chocolate' ? '🍫' : '✨'}
                 </div>
                 <div>
                    <p className="text-2xl font-serif italic">Received a digital {user.receivedComforts[0].type}!</p>
                    <p className="text-xs opacity-70 italic mt-1">Sent with love just now.</p>
                 </div>
              </div>
           </div>
           <span className="absolute bottom-[-20%] right-[-10%] text-[10rem] opacity-10 rotate-12 group-hover:scale-110 transition-transform">💝</span>
        </section>
      )}

      {/* Mood Melodies Selection */}
      <section className="bg-white/50 p-6 rounded-[2.5rem] border border-pink-100/50">
        <h3 className="text-lg font-serif text-pink-500 mb-4 px-2 italic flex items-center gap-2">
          <span className="text-xl">🎶</span> Mood Melodies
        </h3>
        <div className="flex gap-3 overflow-x-auto pb-4 scrollbar-hide px-2">
          {MOODS.map((mood) => (
            <button
              key={mood.label}
              onClick={() => handleMoodSelect(mood)}
              className={`flex-shrink-0 flex flex-col items-center gap-2 p-4 rounded-3xl transition-all border-2 ${selectedMood === mood.label ? 'bg-pink-400 border-pink-400 text-white shadow-lg scale-105' : 'bg-white border-pink-50 text-pink-300 hover:border-pink-200'}`}
            >
              <span className="text-2xl">{mood.emoji}</span>
              <span className="text-[10px] font-bold uppercase tracking-tighter">{mood.label}</span>
            </button>
          ))}
        </div>
      </section>

      {/* Partner Reminders */}
      {activeReminders.length > 0 && (
        <section className="bg-indigo-50/50 p-6 rounded-[2.5rem] border border-indigo-100 shadow-sm">
          <h3 className="text-lg font-serif text-indigo-600 mb-4 flex items-center gap-2 px-2">
            <span className="text-xl">💝</span> From {user.partnerName}
          </h3>
          <div className="space-y-3">
            {activeReminders.map(reminder => (
              <div key={reminder.id} className="flex items-center gap-4 bg-white/90 p-5 rounded-3xl shadow-sm border border-indigo-50 hover:scale-[1.02] transition-transform">
                <div className="w-10 h-10 bg-indigo-100 rounded-full flex items-center justify-center text-xl">💌</div>
                <div>
                  <p className="text-base font-serif italic text-indigo-900 leading-tight">{reminder.text}</p>
                  <p className="text-[9px] text-indigo-400 font-bold uppercase tracking-widest mt-1">{reminder.time}</p>
                </div>
              </div>
            ))}
          </div>
        </section>
      )}

      {/* Main Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {/* Blooming Water Tracker */}
        <div className="bg-white p-8 rounded-[3rem] shadow-sm border border-pink-50 flex flex-col items-center justify-center text-center group">
          <h3 className="text-xl font-serif text-pink-500 mb-6 flex items-center gap-2 italic">
            <span className="text-2xl">💧</span> Hydration Bloom
          </h3>
          <div className="relative w-32 h-32 mb-6">
            <div className="absolute inset-0 border-4 border-pink-50 rounded-full"></div>
