import React, { useState } from 'react';
import { User, Symptom, BirthControlLog, BirthControlConfig, TemperatureLog } from '../types';
import { SYMPTOMS } from '../constants';
import TemperatureTracker from './TemperatureTracker';

interface PeriodTrackerProps {
  user: User;
  symptoms: Symptom[];
  setSymptoms: React.Dispatch<React.SetStateAction<Symptom[]>>;
  bcLogs: BirthControlLog[];
  setBcLogs: React.Dispatch<React.SetStateAction<BirthControlLog[]>>;
  onUpdateBCConfig: (config: BirthControlConfig) => void;
  tempLogs: TemperatureLog[];
  setTempLogs: React.Dispatch<React.SetStateAction<TemperatureLog[]>>;
  onUpdateTempUnit: (unit: 'C' | 'F') => void;
}

const PeriodTracker: React.FC<PeriodTrackerProps> = ({ 
  user, 
  symptoms, 
  setSymptoms, 
  bcLogs, 
  setBcLogs,
  onUpdateBCConfig,
  tempLogs,
  setTempLogs,
  onUpdateTempUnit
}) => {
  const [isSettingBC, setIsSettingBC] = useState(false);
  const [bcMethod, setBcMethod] = useState(user.birthControlConfig?.method || 'Pill');
  const [bcFrequency, setBcFrequency] = useState<BirthControlConfig['frequency']>(user.birthControlConfig?.frequency || 'daily');
  const [bcTime, setBcTime] = useState(user.birthControlConfig?.reminderTime || '09:00');

  const today = new Date().toDateString();
  const isTakenToday = bcLogs.some(log => log.date === today && log.taken);

  const toggleSymptom = (type: Symptom['type']) => {
    const existing = symptoms.find(s => s.type === type && s.date === today);
    if (existing) {
      setSymptoms(symptoms.filter(s => s !== existing));
    } else {
      setSymptoms([...symptoms, {
        id: Math.random().toString(),
        date: today,
        type,
        intensity: 2
      }]);
    }
  };

  const handleLogIntake = () => {
    if (isTakenToday) {
      setBcLogs(bcLogs.filter(log => log.date !== today));
    } else {
      setBcLogs([...bcLogs, { date: today, taken: true }]);
    }
  };

  const saveBCConfig = () => {
    onUpdateBCConfig({
      method: bcMethod,
      frequency: bcFrequency,
      reminderTime: bcTime,
      enabled: true
    });
    setIsSettingBC(false);
  };

  const getDayStatus = (day: number) => {
    const pStart = 1;
    const pEnd = user.periodLength || 5;
    const cycleLen = user.cycleLength || 28;
    const ovulationDay = cycleLen - 14;
    const fertileStart = ovulationDay - 4;
    const fertileEnd = ovulationDay + 1;

    if (day >= pStart && day <= pEnd) return 'period';
    if (day === ovulationDay) return 'ovulation';
    if (day >= fertileStart && day <= fertileEnd) return 'fertile';
    if (day > pEnd && day < fertileStart) return 'follicular';
    if (day > fertileEnd && day <= cycleLen) return 'luteal';
    return 'none';
  };

  const dayStyles = {
    period: 'bg-pink-400 text-white font-bold shadow-md shadow-pink-100',
    ovulation: 'bg-teal-400 text-white font-bold shadow-md shadow-teal-100 ring-2 ring-teal-200',
    fertile: 'bg-teal-50 text-teal-600 font-medium border border-teal-100',
    follicular: 'bg-emerald-50 text-emerald-600 border border-emerald-100/50',
    luteal: 'bg-orange-50 text-orange-600 border border-orange-100/50',
    none: 'hover:bg-pink-50 text-gray-400'
  };

  return (
    <div className="space-y-8 animate-fadeIn pb-12">
      <header className="text-center">
        <h2 className="text-3xl font-serif text-pink-500 italic">Cycle Sanctuary</h2>
        <p className="text-sm text-pink-300 italic">Your body, your rhythm, your power</p>
      </header>

      {/* Birth Control Tracker */}
      <section className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-pink-50 relative overflow-hidden">
        <div className="flex justify-between items-center mb-6">
          <h3 className="text-xl font-serif text-pink-500 flex items-center gap-2 italic">
            <span className="text-2xl">💊</span> Birth Control
          </h3>
          <button 
            onClick={() => setIsSettingBC(!isSettingBC)}
            className="text-[10px] font-bold text-pink-300 uppercase hover:text-pink-500 transition-colors"
          >
            {isSettingBC ? 'Close' : 'Configure'}
          </button>
        </div>

        {isSettingBC ? (
          <div className="space-y-6 animate-fadeIn">
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <label className="text-[10px] font-bold text-pink-300 uppercase ml-2">Method</label>
                <select 
                  value={bcMethod}
                  onChange={(e) => setBcMethod(e.target.value)}
                  className="w-full bg-pink-50/50 p-3 rounded-2xl outline-none text-pink-600 font-bold text-sm border border-transparent focus:border-pink-200"
                >
                  {['Pill', 'Patch', 'Ring', 'Injection', 'IUD', 'Implant'].map(m => (
                    <option key={m} value={m}>{m}</option>
                  ))}
                </select>
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-bold text-pink-300 uppercase ml-2">Frequency</label>
                <select 
                  value={bcFrequency}
                  onChange={(e) => setBcFrequency(e.target.value as any)}
                  className="w-full bg-pink-50/50 p-3 rounded-2xl outline-none text-pink-600 font-bold text-sm border border-transparent focus:border-pink-200"
                >
                  <option value="daily">Daily</option>
                  <option value="weekly">Weekly</option>
                  <option value="monthly">Monthly</option>
                </select>
              </div>
            </div>
            <div className="space-y-2">
              <label className="text-[10px] font-bold text-pink-300 uppercase ml-2">Reminder Time</label>
              <input 
                type="time" 
                value={bcTime}
                onChange={(e) => setBcTime(e.target.value)}
                className="w-full bg-pink-50/50 p-3 rounded-2xl outline-none text-pink-600 font-bold text-sm border border-transparent focus:border-pink-200"
              />
            </div>
            <button 
              onClick={saveBCConfig}
              className="w-full py-4 bg-pink-400 text-white rounded-2xl font-bold uppercase tracking-widest text-[10px] shadow-lg shadow-pink-100"
            >
              Save Settings
            </button>
          </div>
        ) : (
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-4">
              <div className={`w-14 h-14 rounded-full flex items-center justify-center text-2xl transition-all shadow-inner ${isTakenToday ? 'bg-pink-400 text-white' : 'bg-pink-50 text-pink-200'}`}>
                {isTakenToday ? '✨' : '💊'}
              </div>
              <div>
                <p className="font-serif italic text-lg text-pink-600">
                  {user.birthControlConfig?.enabled ? user.birthControlConfig.method : 'Track your method'}
                </p>
                <p className="text-[10px] font-bold text-pink-300 uppercase tracking-widest">
                  {user.birthControlConfig?.enabled ? `${user.birthControlConfig.frequency} • ${user.birthControlConfig.reminderTime}` : 'Tap configure to start'}
                </p>
              </div>
            </div>
            <button 
              onClick={handleLogIntake}
              className={`px-6 py-3 rounded-full font-bold text-[10px] uppercase tracking-widest transition-all ${isTakenToday ? 'bg-pink-50 text-pink-400' : 'bg-pink-400 text-white shadow-lg shadow-pink-100 hover:scale-105 active:scale-95'}`}
            >
              {isTakenToday ? 'Taken Today' : 'Log Intake'}
            </button>
          </div>
        )}
      </section>

      {/* Temperature Tracker Component */}
      <TemperatureTracker 
        user={user} 
        logs={tempLogs} 
        setLogs={setTempLogs} 
        onUpdateUnit={onUpdateTempUnit} 
      />

      {/* Calendar Preview */}
      <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-pink-50">
        <div className="flex justify-between items-center mb-6 px-2">
           <h3 className="font-serif text-xl text-pink-600 italic">March 2024</h3>
           <div className="flex gap-2">
              <button className="w-8 h-8 rounded-full bg-pink-50 text-pink-400 flex items-center justify-center hover:bg-pink-100 transition-colors">←</button>
              <button className="w-8 h-8 rounded-full bg-pink-50 text-pink-400 flex items-center justify-center hover:bg-pink-100 transition-colors">→</button>
           </div>
        </div>

        <div className="grid grid-cols-7 gap-2 text-center text-[10px] font-bold text-pink-300 uppercase mb-4">
          <span>Mon</span><span>Tue</span><span>Wed</span><span>Thu</span><span>Fri</span><span>Sat</span><span>Sun</span>
        </div>

        <div className="grid grid-cols-7 gap-3">
          {[...Array(2)].map((_, i) => <div key={`empty-${i}`} />)}

          {[...Array(31)].map((_, i) => {
            const dayNum = i + 1;
            const status = getDayStatus(dayNum);

            return (
              <div 
                key={i} 
                className={`relative aspect-square flex items-center justify-center rounded-2xl text-[10px] md:text-sm transition-all cursor-pointer ${dayStyles[status]}`}
              >
                {dayNum}
                {status === 'ovulation' && (
                  <span className="absolute -top-1 -right-1 text-[10px]">✨</span>
                )}
              </div>
            );
          })}
        </div>

        {/* Dynamic Legend */}
        <div className="mt-10 grid grid-cols-2 md:grid-cols-4 gap-3">
           <div className="flex items-center gap-2 p-2 bg-pink-50/50 rounded-xl border border-pink-100/50">
              <div className="w-3 h-3 bg-pink-400 rounded-sm shadow-sm"></div>
              <span className="text-[8px] text-pink-500 uppercase font-black leading-none">Period</span>
           </div>
           <div className="flex items-center gap-2 p-2 bg-emerald-50/50 rounded-xl border border-emerald-100/50">
              <div className="w-3 h-3 bg-emerald-400 rounded-sm shadow-sm"></div>
              <span className="text-[8px] text-emerald-600 uppercase font-black leading-none">Follicular</span>
           </div>
           <div className="flex items-center gap-2 p-2 bg-teal-50/50 rounded-xl border border-teal-100/50">
              <div className="w-3 h-3 bg-teal-400 rounded-sm shadow-sm"></div>
              <span className="text-[8px] text-teal-600 uppercase font-black leading-none">Ovulatory</span>
           </div>
           <div className="flex items-center gap-2 p-2 bg-orange-50/50 rounded-xl border border-orange-100/50">
              <div className="w-3 h-3 bg-orange-400 rounded-sm shadow-sm"></div>
              <span className="text-[8px] text-orange-600 uppercase font-black leading-none">Luteal</span>
           </div>
        </div>
      </div>

      <section>
        <h3 className="text-xl font-serif text-pink-500 mb-4 px-2">How are you feeling today?</h3>
        <div className="grid grid-cols-3 gap-4">
          {SYMPTOMS.map((s) => {
             const isActive = symptoms.some(item => item.type === s.id && item.date === today);
             return (
               <button 
                 key={s.id}
                 onClick={() => toggleSymptom(s.id as any)}
                 className={`group flex flex-col items-center gap-3 p-6 rounded-[2.5rem] transition-all border-2 relative overflow-hidden ${isActive ? 'bg-pink-100 border-pink-300 shadow-lg shadow-pink-100 scale-105' : 'bg-white border-pink-50 hover:border-pink-200'}`}
               >
                 {isActive && (
                   <div className="absolute top-0 right-0 p-2">
                     <div className="w-2 h-2 bg-pink-400 rounded-full animate-ping"></div>
                   </div>
                 )}
                 <span className={`text-4xl transition-transform group-hover:scale-110 ${isActive ? 'animate-bounce' : ''}`}>{s.emoji}</span>
                 <span className={`text-[10px] font-bold uppercase tracking-tighter ${isActive ? 'text-pink-600' : 'text-pink-300'}`}>{s.label}</span>
               </button>
             );
          })}
        </div>
      </section>

      <div className="p-8 bg-gradient-to-br from-pink-500 to-rose-400 rounded-[2.5rem] text-white shadow-xl shadow-pink-200 relative overflow-hidden">
        <div className="relative z-10">
          <p className="text-xs font-bold uppercase tracking-widest opacity-80 mb-2">Cycle Wisdom</p>
          <p className="text-xl font-serif italic leading-relaxed">
            "Your body is a blooming garden. Honor each season with love and patience."
          </p>
        </div>
        <span className="absolute -bottom-10 -right-10 text-[12rem] opacity-10">✨</span>
      </div>
    </div>
  );
};

