            <button 
              onClick={saveBCConfig}
              className="w-full py-4 bg-pink-400 text-white rounded-2xl font-bold uppercase tracking-widest text-[10px] shadow-lg shadow-pink-100"
            >
              Save Settings
            </button>
          </div>
        ) : (
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-4">
              <div className={`w-14 h-14 rounded-full flex items-center justify-center text-2xl transition-all shadow-inner ${isTakenToday ? 'bg-pink-400 text-white' : 'bg-pink-50 text-pink-200'}`}>
                {isTakenToday ? '✨' : '💊'}
              </div>
              <div>
                <p className="font-serif italic text-lg text-pink-600">
                  {user.birthControlConfig?.enabled ? user.birthControlConfig.method : 'Track your method'}
                </p>
                <p className="text-[10px] font-bold text-pink-300 uppercase tracking-widest">
                  {user.birthControlConfig?.enabled ? `${user.birthControlConfig.frequency} • ${user.birthControlConfig.reminderTime}` : 'Tap configure to start'}
                </p>
              </div>
            </div>
            <button 
              onClick={handleLogIntake}
              className={`px-6 py-3 rounded-full font-bold text-[10px] uppercase tracking-widest transition-all ${isTakenToday ? 'bg-pink-50 text-pink-400' : 'bg-pink-400 text-white shadow-lg shadow-pink-100 hover:scale-105 active:scale-95'}`}
            >
              {isTakenToday ? 'Taken Today' : 'Log Intake'}
            </button>
          </div>
        )}
      </section>

      {/* Temperature Tracker Component */}
      <TemperatureTracker 
        user={user} 
        logs={tempLogs} 
        setLogs={setTempLogs} 
        onUpdateUnit={onUpdateTempUnit} 
      />

      {/* Calendar Preview */}
      <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-pink-50">
        <div className="flex justify-between items-center mb-6 px-2">
           <h3 className="font-serif text-xl text-pink-600 italic">March 2024</h3>
           <div className="flex gap-2">
              <button className="w-8 h-8 rounded-full bg-pink-50 text-pink-400 flex items-center justify-center hover:bg-pink-100 transition-colors">←</button>
              <button className="w-8 h-8 rounded-full bg-pink-50 text-pink-400 flex items-center justify-center hover:bg-pink-100 transition-colors">→</button>
           </div>
        </div>

        <div className="grid grid-cols-7 gap-2 text-center text-[10px] font-bold text-pink-300 uppercase mb-4">
          <span>Mon</span><span>Tue</span><span>Wed</span><span>Thu</span><span>Fri</span><span>Sat</span><span>Sun</span>
        </div>

        <div className="grid grid-cols-7 gap-3">
          {[...Array(2)].map((_, i) => <div key={`empty-${i}`} />)}

          {[...Array(31)].map((_, i) => {
            const dayNum = i + 1;
            const status = getDayStatus(dayNum);

            return (
              <div 
                key={i} 
                className={`relative aspect-square flex items-center justify-center rounded-2xl text-[10px] md:text-sm transition-all cursor-pointer ${dayStyles[status]}`}
              >
                {dayNum}
                {status === 'ovulation' && (
                  <span className="absolute -top-1 -right-1 text-[10px]">✨</span>
                )}
              </div>
            );
          })}
        </div>

        {/* Dynamic Legend */}
        <div className="mt-10 grid grid-cols-2 md:grid-cols-4 gap-3">
           <div className="flex items-center gap-2 p-2 bg-pink-50/50 rounded-xl border border-pink-100/50">
              <div className="w-3 h-3 bg-pink-400 rounded-sm shadow-sm"></div>
              <span className="text-[8px] text-pink-500 uppercase font-black leading-none">Period</span>
           </div>
           <div className="flex items-center gap-2 p-2 bg-blue-50/50 rounded-xl border border-blue-100/50">
              <div className="w-3 h-3 bg-blue-400 rounded-sm shadow-sm"></div>
              <span className="text-[8px] text-blue-600 uppercase font-black leading-none">Follicular</span>
           </div>
           <div className="flex items-center gap-2 p-2 bg-teal-50/50 rounded-xl border border-teal-100/50">
              <div className="w-3 h-3 bg-teal-400 rounded-sm shadow-sm"></div>
              <span className="text-[8px] text-teal-600 uppercase font-black leading-none">Ovulatory</span>
           </div>
           <div className="flex items-center gap-2 p-2 bg-orange-50/50 rounded-xl border border-orange-100/50">
              <div className="w-3 h-3 bg-orange-400 rounded-sm shadow-sm"></div>
              <span className="text-[8px] text-orange-600 uppercase font-black leading-none">Luteal</span>
           </div>
        </div>
      </div>

      <section>
        <h3 className="text-xl font-serif text-pink-500 mb-4 px-2">How are you feeling today?</h3>
        <div className="grid grid-cols-3 gap-4">
          {SYMPTOMS.map((s) => {
             const isActive = symptoms.some(item => item.type === s.id && item.date === today);
             return (
               <button 
                 key={s.id}
                 onClick={() => toggleSymptom(s.id as any)}
                 className={`group flex flex-col items-center gap-3 p-6 rounded-[2.5rem] transition-all border-2 relative overflow-hidden ${isActive ? 'bg-pink-100 border-pink-300 shadow-lg shadow-pink-100 scale-105' : 'bg-white border-pink-50 hover:border-pink-200'}`}
               >
                 {isActive && (
                   <div className="absolute top-0 right-0 p-2">
                     <div className="w-2 h-2 bg-pink-400 rounded-full animate-ping"></div>
                   </div>
                 )}
                 <span className={`text-4xl transition-transform group-hover:scale-110 ${isActive ? 'animate-bounce' : ''}`}>{s.emoji}</span>
                 <span className={`text-[10px] font-bold uppercase tracking-tighter ${isActive ? 'text-pink-600' : 'text-pink-300'}`}>{s.label}</span>
               </button>
             );
          })}
        </div>
      </section>

      <div className="p-8 bg-gradient-to-br from-pink-500 to-rose-400 rounded-[2.5rem] text-white shadow-xl shadow-pink-200 relative overflow-hidden">
        <div className="relative z-10">
          <p className="text-xs font-bold uppercase tracking-widest opacity-80 mb-2">Cycle Wisdom</p>
          <p className="text-xl font-serif italic leading-relaxed">
            "Your body is a blooming garden. Honor each season with love and patience."
          </p>
        </div>
        <span className="absolute -bottom-10 -right-10 text-[12rem] opacity-10">✨</span>
      </div>
    </div>
  );
};

export default PeriodTracker;
